const trigger = $input.first().json;
const body = trigger.body || trigger;
const entry = body?.entry?.[0];
const change = entry?.changes?.[0];
const value = change?.value;
const msg = value?.messages?.[0];

if (!msg || !msg.from) return [];

const phoneNumber = msg.from;
const pushName = (value?.contacts?.[0]?.profile?.name || '').split(' ')[0];
const conversationId = phoneNumber;
const messageType = msg.type;

let messageText = '';
if (messageType === 'text') {
  messageText = (msg.text?.body || '').trim();
} else {
  const labels = { audio: 'áudio', image: 'imagem', video: 'vídeo', document: 'documento', sticker: 'figurinha' };
  messageText = '[Lead enviou ' + (labels[messageType] || messageType) + ']';
}

if (!messageText) return [];
return [{ json: { phoneNumber, pushName, conversationId, messageText, messageType } }];

const data = $('Extrair Dados').first().json;
const { phoneNumber, pushName, conversationId, messageText } = data;

const oneDayAgo = new Date(Date.now() - 24 * 3600 * 1000).toISOString();
const rawSheets = $('Buscar Histórico').first().json;
const rows = rawSheets.values || [];
const headers = rows[0] || [];
const allRows = rows.slice(1).map(row => {
  const obj = {};
  headers.forEach((h, i) => { obj[h] = row[i] || ''; });
  return { json: obj };
});

const history = allRows
  .filter(r => r.json.conversationId === conversationId || r.json.conversationId === 'scala_' + conversationId)
  .filter(r => !r.json.timestamp || r.json.timestamp >= oneDayAgo)
  .sort((a, b) => new Date(a.json.timestamp || 0) - new Date(b.json.timestamp || 0))
  .slice(-20)
  .map(r => ({ role: r.json.role, content: r.json.content }))
  .filter(m => (m.role === 'user' || m.role === 'assistant') && typeof m.content === 'string' && m.content.trim());

const lastUser = history.filter(m => m.role === 'user').slice(-1)[0];
if (lastUser && lastUser.content === messageText) return [];

const isFirstMessage = history.length === 0;

const slots = [];
const d = new Date();
d.setMinutes(0, 0, 0);
d.setHours(d.getHours() + 2);
for (let i = 0; i < 300 && slots.length < 6; i++) {
  const day = d.getDay(), hour = d.getHours();
  if (day === 0) { d.setDate(d.getDate() + 1); d.setHours(9); continue; }
  if (day === 6) { d.setDate(d.getDate() + 2); d.setHours(9); continue; }
  if (hour < 9)  { d.setHours(9); continue; }
  if (hour >= 17){ d.setDate(d.getDate() + 1); d.setHours(9); continue; }
  const dn = ['dom','seg','ter','qua','qui','sex','sáb'][day];
  slots.push(dn + ' ' + String(d.getDate()).padStart(2,'0') + '/' + String(d.getMonth()+1).padStart(2,'0') + ' às ' + String(hour).padStart(2,'0') + ':00');
  d.setHours(hour + 2);
}
const slotsText = slots.join('
');

const nome = pushName || '';
const nomeStr = nome ? nome : 'você';

const fromSite = isFirstMessage && /vim pelo site|diagn[oó]stico gratuito|quero agendar.*diagn[oó]s/i.test(messageText);

