const ctx = $('Montar Contexto').first().json;
const gpt = $input.first().json;
const aiResponse = (gpt.choices?.[0]?.message?.content || '').trim()
  || 'Oi! Tive um probleminha aqui. Pode repetir sua mensagem?';
return [{ json: { aiResponse, phoneNumber: ctx.phoneNumber, conversationId: ctx.conversationId, pushName: ctx.pushName, messageText: ctx.messageText } }];

const ctx = $('Preparar Resposta').first().json;
const ts = new Date().toISOString();
const userRow = [ctx.conversationId, 'user',      ctx.messageText, ctx.pushName || '', ts];
const aiRow   = [ctx.conversationId, 'assistant', ctx.aiResponse,  ctx.pushName || '', ts];
return [{ json: { values: [userRow, aiRow] } }];

const ctx = $('Preparar Resposta').first().json;
const { aiResponse, pushName, phoneNumber } = ctx;

const isBooking = /marcado para|agendado para/i.test(aiResponse);
if (!isBooking) return [{ json: { ...ctx, isBooking: false } }];

const dateMatch = aiResponse.match(/(\d{2})\/(\d{2})\s+às\s+(\d{2}):(\d{2})/);
if (!dateMatch) return [{ json: { ...ctx, isBooking: false } }];

const [_, day, month, hour, minute] = dateMatch;
const year = new Date().getFullYear();
const pad = n => String(n).padStart(2, '0');

const startISO = `${year}-${pad(parseInt(month))}-${pad(parseInt(day))}T${pad(parseInt(hour))}:${pad(parseInt(minute))}:00`;
const totalEndMin = parseInt(minute) + 20;
const endHour = parseInt(hour) + Math.floor(totalEndMin / 60);
const endMin = totalEndMin % 60;
const endISO = `${year}-${pad(parseInt(month))}-${pad(parseInt(day))}T${pad(endHour)}:${pad(endMin)}:00`;

return [{ json: {
  ...ctx,
  isBooking: true,
  eventTitle: 'Diagnóstico Gratuito Scala — ' + (pushName || phoneNumber),
  eventDesc: 'Lead: ' + (pushName || 'não identificado') + '\nTelefone: ' + phoneNumber + '\nAgendado via WhatsApp',
  startISO,
  endISO,
  requestId: 'diag-' + Date.now()
} }];

const ctx = $('Detectar Agendamento').first().json;
const cal = $input.first().json;

const meetLink = cal?.conferenceData?.entryPoints?.[0]?.uri || null;

let aiResponse = ctx.aiResponse || '';
if (meetLink) {
  aiResponse = aiResponse
    .replace(/O link do Google Meet vai direto aqui após confirmar\.?/gi, '')
    .replace(/Paulo vai [^\n.]*Google Meet[^\n.]*[.!]?/gi, '')
    .replace(/Link do Google Meet:?\s*\n?https?:\/\/[^\s]*/gi, '')
    .trim();
  aiResponse = aiResponse + '\n🔗 ' + meetLink;
}

return [{ json: { ...ctx, aiResponse } }];
